={
  "fields": {
    "project": { "id": "10000" },
    "summary": {{ JSON.stringify($fromAI('Summary', 'One-line summary of the IT issue', 'string')) }},
    "issuetype": { "name": {{ JSON.stringify((() => { const raw = ($fromAI('IssueType', "Pick exactly one word based on the nature of the question: 'Story' if it is a feature request or improvement idea, otherwise 'Task' for routine how-to/requests or problem reports", 'string') || '').toLowerCase(); return raw.includes('story') ? 'Story' : 'Task'; })()) }} },
    "description": {
      "type": "doc",
      "version": 1,
      "content": [
        {
          "type": "paragraph",
          "content": [
            { "type": "text", "text": {{ JSON.stringify($fromAI('Description', 'Full description of the issue, including what the user reported and relevant context', 'string')) }} }
          ]
        }
      ]
    }
  }
}

={
  "message": {
    "subject": {{ JSON.stringify('New IT Support Ticket: ' + $fromAI('Summary', 'One-line summary of the IT issue/ticket that was just created', 'string')) }},
    "body": {
      "contentType": "Text",
      "content": {{ JSON.stringify('Summary: ' + $fromAI('Summary', 'One-line summary of the IT issue/ticket that was just created', 'string') + '\n\nRecommended next step: ' + $fromAI('NextStep', 'A concrete recommended next step for IT or the user to take on this ticket', 'string') + '\n\nJira ticket: https://YOUR-DOMAIN.atlassian.net/browse/' + $fromAI('TicketKey', 'The Jira issue key returned by the Create Jira Ticket tool call just now, e.g. KAN-123 - read it from that tool result, do not invent it', 'string')) }}
    },
    "toRecipients": [ { "emailAddress": { "address": "your-email@outlook.com" } } ]
  }
}
